@Configuration
class GatewayRouteConfig(private val authFilter: AuthenticationGatewayFilter) {
    @Bean
    fun routeLocator(builder: RouteLocatorBuilder): RouteLocator =
        builder.routes()
            .route("auth-service") { r -> r.path("/api/auth/**").uri("lb://auth-service") }
            .route("gifticon-service") { r -> r.path("/api/gifticons/**").filters { f -> f.filter(authFilter.apply(...)) }.uri("lb://gifticon-service") }
            .build()
}

class AuthenticationGatewayFilter(...) : AbstractGatewayFilterFactory<...>(...) {
    override fun apply(config: Config): GatewayFilter = GatewayFilter { exchange, chain ->
        val token = jwtTokenValidator.extractFromHeader(authHeader)
        val claims = jwtTokenValidator.validateAndExtract(token)
        val mutatedRequest = request.mutate().header("X-User-Id", userId).header("X-User-Roles", roles).build()
        chain.filter(exchange.mutate().request(mutatedRequest).build())
    }
}

@Configuration
class CorsConfig {
    @Bean
    fun corsWebFilter(): CorsWebFilter {
        val config = CorsConfiguration().apply {
            allowedOrigins = listOf("http://localhost:5173", "http://localhost:5174")
            allowedMethods = listOf("GET", "POST", "PUT", "DELETE")
        }
    }
}
